+async fn setup_connector(mock_url: &str) -> AmplitudeConnector {
+    let mut c = AmplitudeConnector::new();
+    c.handle_configure(json!({
+        "api_key": "test_api_key",
+        "secret_key": "test_secret_key",
+        "base_url": mock_url
+    }))
+    .await
+    .unwrap();
+    c.handle_handshake(json!({"session_id": "test"}))
+        .await
+        .unwrap();
+    c
