+            "capability": "bigquery.tables.read",
+            "risk_level": "low",
+            "safety_tier": "safe",
+            "idempotency": "strict",
+        },
+        {
+            "id": "bigquery.jobs.list",
+            "summary": "List recent jobs",
+            "capability": "bigquery.jobs.read",
+            "risk_level": "low",
+            "safety_tier": "safe",
+            "idempotency": "strict",
+        },
+        {
+            "id": "bigquery.jobs.query",
